import {
  pgTable,
  uuid,
  varchar,
  text,
  numeric,
  integer,
  boolean,
  timestamp,
  index,
} from "drizzle-orm/pg-core";
import { createInsertSchema, createSelectSchema } from "drizzle-zod";
import { z } from "zod/v4";
import { backtestRunsTable } from "./backtest-runs";
import { portfolioBacktestsTable } from "./portfolio-backtests";
import { walkForwardRunsTable } from "./walk-forward-runs";

/**
 * Strategy validation report.
 * Generated by the validation engine after a backtest / walk-forward run.
 *
 * Flags are boolean red-flags. Recommendation is a human-readable verdict.
 * findings: JSON array of { flag, severity, message } objects.
 */
export const validationResultsTable = pgTable(
  "validation_results",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    /** Source run — at most one FK is non-null */
    backtestRunId: uuid("backtest_run_id").references(() => backtestRunsTable.id),
    portfolioBacktestId: uuid("portfolio_backtest_id").references(
      () => portfolioBacktestsTable.id,
    ),
    walkForwardRunId: uuid("walk_forward_run_id").references(() => walkForwardRunsTable.id),
    /** 0–100 composite score; higher = better-validated strategy */
    overallScore: integer("overall_score").notNull(),
    /** Grade: A | B | C | D | F */
    grade: varchar("grade", { length: 2 }).notNull(),
    /** Red-flag indicators */
    overfittingFlag: boolean("overfitting_flag").notNull().default(false),
    insufficientSampleFlag: boolean("insufficient_sample_flag").notNull().default(false),
    excessiveDrawdownFlag: boolean("excessive_drawdown_flag").notNull().default(false),
    lowTradeCountFlag: boolean("low_trade_count_flag").notNull().default(false),
    strategyInstabilityFlag: boolean("strategy_instability_flag").notNull().default(false),
    /** JSON array of { flag, severity, message } */
    findings: text("findings").notNull(),
    /** Plain-text verdict for display */
    recommendation: text("recommendation").notNull(),
    /** Minimum trades threshold used (e.g. 30) */
    minTradesThreshold: integer("min_trades_threshold").notNull().default(30),
    /** Drawdown threshold used (e.g. 0.3 = 30%) */
    maxDrawdownThreshold: numeric("max_drawdown_threshold", { precision: 8, scale: 4 }).notNull().default("0.30"),
    generatedAt: timestamp("generated_at", { withTimezone: true }).notNull().defaultNow(),
    createdAt: timestamp("created_at", { withTimezone: true }).notNull().defaultNow(),
  },
  (table) => [
    index("validation_results_run_id_idx").on(table.backtestRunId),
    index("validation_results_portfolio_id_idx").on(table.portfolioBacktestId),
    index("validation_results_wf_id_idx").on(table.walkForwardRunId),
    index("validation_results_grade_idx").on(table.grade),
    index("validation_results_generated_at_idx").on(table.generatedAt),
  ],
);

export const insertValidationResultSchema = createInsertSchema(validationResultsTable).omit({
  id: true,
  createdAt: true,
});
export const selectValidationResultSchema = createSelectSchema(validationResultsTable);

export type InsertValidationResult = z.infer<typeof insertValidationResultSchema>;
export type ValidationResult = typeof validationResultsTable.$inferSelect;
